# Thread-safe tracking of cardinality
class CardinalityTracker:
    def __init__(self):
        self.lock = threading.Lock()
        self.user_ids = set()
        self.paths = set()
        self.combinations = set()
        
    def can_add(self, user_id, path):
        with self.lock:
            combo = (user_id, path)
            
